import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{i,n as a,r as o,t as s}from"./chunks/windows-wizard-screenshot.QBlzzreT.js";const c=JSON.parse(`{"title":"在 Windows 上安装 Java","description":"在 Windows 上安装 Java 的逐步指南。","frontmatter":{"title":"在 Windows 上安装 Java","description":"在 Windows 上安装 Java 的逐步指南。","authors":["IMB11","skycatminepokie"],"next":false,"files":[]},"headers":[],"relativePath":"zh_cn/players/installing-java/windows.md","filePath":"translated/zh_cn/players/installing-java/windows.md","lastUpdated":1772272927000}`);var l={name:`zh_cn/players/installing-java/windows.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">在 Windows 上安装 Java <a class="header-anchor" href="#h1" aria-label="Permalink to “在 Windows 上安装 Java”">​</a></h1><p>这个指南将会指引您在 Windows 上安装 Java 21。</p><p>Minecraft 启动器附带了自己的 Java 安装，因此这部分只在你想使用 Fabric 的 <code>.jar</code> 安装器，或者你想使用 Minecraft 服务器的 <code>.jar</code> 时有关。</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. 检查 Java 是否已经安装 <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. 检查 Java 是否已经安装”">​</a></h2><p>要检查 Java 是否已安装，你首先必须打开命令提示符。</p><p>命令提示符可以通过按下 <kbd>Windows</kbd>+<kbd>R</kbd> 再在弹出的窗口中输入 <code>cmd.exe</code> 来打开。</p><p><img src="/assets/players/installing-java/windows-run-dialog.png" alt="Windows 运行对话框中的“cmd.exe”" loading="lazy"></p><p>打开命令提示符后，输入 <code>java -version</code> 并按下 <kbd>Enter</kbd> 键。</p><p>如果命令成功运行，你会看到类似这样的内容。 如果命令运行失败，请继续进行下一步。</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="输入了“java -version”的命令提示符" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>要使用 Minecraft 1.21.11，至少需要安装 Java 21。</p><p>如果此命令显示的版本低于 21，则需要更新现有的 Java 安装，请继续阅读本页。</p></div><h2 id="2-download-the-java-installer" tabindex="-1">2. 下载 Java 21 安装程序 <a class="header-anchor" href="#2-download-the-java-installer" aria-label="Permalink to “2. 下载 Java 21 安装程序”">​</a></h2><p>要安装 Java 21，你需要从 <a href="https://adoptium.net/temurin/releases?version=21&amp;os=windows&amp;arch=any&amp;mode=filter" target="_blank" rel="noreferrer">Adoptium</a> 下载安装程序。</p><p>你需要下载 <code>Windows Installer (.msi)</code> 版本：</p><p><img src="/assets/players/installing-java/windows-download-java.png" alt="Adoptium 下载页面，高亮标出了 Windows 安装程序 (.msi)" loading="lazy"></p><p>如果你使用的是 32 位操作系统，请选择 <code>x86</code>；如果你使用的是 64 位操作系统，请选择 <code>x64</code>。</p><p>大多数现代电脑都运行 64 位操作系统。 如果你不确定，试着下载 64 位的版本。</p><h2 id="3-run-the-installer" tabindex="-1">3. 运行安装器！ <a class="header-anchor" href="#3-run-the-installer" aria-label="Permalink to “3. 运行安装器！”">​</a></h2><p>按照安装程序的步骤安装 Java 21。 到达这一页时，应该将以下功能设置为“整个功能将安装在本地硬盘上”：</p><ul><li><code>设置或重写 JAVA_HOME 变量</code>——这会被添加到你的 PATH 中。</li><li><code>JavaSoft (Oracle) registry keys</code></li></ul><p><img src="/assets/players/installing-java/windows-wizard-screenshot.png" alt="高亮了“设置或重写 JAVA_HOME 变量”和“JavaSoft (Oracle) registry keys”的 Java 21 安装器" loading="lazy"></p><p>做完这些后，你可以点击 <code>下一步</code> 并继续安装。</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>在你重启计算机之前，Windows 可能不会将 Java 已安装这一信息告知其他程序。</p><p><strong>继续操作前，请务必重启计算机！</strong></p></div><h2 id="4-verify-that-java-is-installed" tabindex="-1">4. 验证是否已安装 Java 21 <a class="header-anchor" href="#4-verify-that-java-is-installed" aria-label="Permalink to “4. 验证是否已安装 Java 21”">​</a></h2><p>安装完成后，你可以打开命令提示符并输入 <code>java -version</code> 来验证 Java 21 是否已安装。</p><p>若命令执行成功，你将看到与前文类似的界面，其中会显示 Java 版本：</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="输入了“java -version”的命令提示符" loading="lazy"></p><p>如有任何问题，欢迎在 <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 频道中提问。</p>`,28)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};